'use server'

import { createClient } from '@/lib/supabase/server'
import { revalidatePath } from 'next/cache'
import {
    MedicalRecord,
    CreateMedicalRecordInput,
    Prescription,
    CreatePrescriptionInput,
    UpdatePatientMedicalInfoInput
} from '@/types/medical-records'

// Medical Records CRUD

export async function getMedicalRecords(contactId: string) {
    const supabase = await createClient()

    const { data, error } = await supabase
        .from('medical_records')
        .select(`
      *,
      doctor:profiles!medical_records_doctor_id_fkey(id, full_name, email)
    `)
        .eq('contact_id', contactId)
        .order('created_at', { ascending: false })

    if (error) {
        console.error('Error fetching medical records:', error)
        return []
    }

    return data as MedicalRecord[]
}

export async function getMedicalRecordById(id: string) {
    const supabase = await createClient()

    const { data, error } = await supabase
        .from('medical_records')
        .select(`
      *,
      doctor:profiles!medical_records_doctor_id_fkey(id, full_name, email),
      contact:crm_contacts!medical_records_contact_id_fkey(id, full_name, birth_date, gender)
    `)
        .eq('id', id)
        .single()

    if (error) {
        console.error('Error fetching medical record:', error)
        return null
    }

    return data as MedicalRecord
}

export async function createMedicalRecord(data: CreateMedicalRecordInput) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) throw new Error('Unauthorized')

    // Prepare payload
    const payload = {
        ...data,
        user_id: user.id, // Record creator
        doctor_id: user.id, // Assuming creator is the doctor, or we should verify role
        record_status: 'completed', // Default to completed for now, or 'draft'
    }

    const { data: record, error } = await supabase
        .from('medical_records')
        .insert(payload as never)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath(`/medical-records`)
    return record as MedicalRecord
}

// Prescriptions

export async function getPrescriptions(contactId: string) {
    const supabase = await createClient()

    const { data, error } = await supabase
        .from('medical_prescriptions')
        .select(`
      *,
      doctor:profiles!medical_prescriptions_doctor_id_fkey(id, full_name),
      contact:crm_contacts!medical_prescriptions_contact_id_fkey(id, full_name)
    `)
        .eq('contact_id', contactId)
        .order('created_at', { ascending: false })

    if (error) {
        console.error('Error fetching prescriptions:', error)
        return []
    }

    return data as Prescription[]
}

export async function createPrescription(data: CreatePrescriptionInput) {
    const supabase = await createClient()
    const { data: { user } } = await supabase.auth.getUser()

    if (!user) throw new Error('Unauthorized')

    const payload = {
        ...data,
        doctor_id: user.id,
        prescription_date: new Date().toISOString(),
        is_printed: false,
    }

    const { data: prescription, error } = await supabase
        .from('medical_prescriptions')
        .insert(payload as never)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath(`/medical-records`)
    return prescription as Prescription
}

// Patient Extra Info (Allergies, Conditions, etc.)
// Assumes these are stored in crm_contacts, potentially in JSONB 'medical_info' column or 'custom_fields'
// or specific columns if migrated.
// For this implementation, let's assume we map them to specific columns if they exist, or `custom_fields`.
// Checking types/crm.ts, we have custom_fields.
// Let's assume we store "medical_info" inside custom_fields or as a separate jsonb column 'medical_info'.
// Better yet, let's check if the user had a `patients` table in the old system.
// The old code used `crm_contacts`.
// We will upsert into `custom_fields.medical_info` for flexibility.

export async function updatePatientMedicalInfo(contactId: string, info: UpdatePatientMedicalInfoInput) {
    const supabase = await createClient()

    // First get current data to merge
    const { data: contactData, error: fetchError } = await supabase
        .from('crm_contacts')
        .select('custom_fields')
        .eq('id', contactId)
        .single()

    if (fetchError) throw new Error(fetchError.message)

    const contact = contactData as { custom_fields: Record<string, unknown> } | null
    const currentCustomFields = (contact?.custom_fields || {}) as Record<string, unknown>
    const currentMedicalInfo = (currentCustomFields.medical_info || {}) as Record<string, unknown>

    // Merge new info
    const newMedicalInfo = {
        ...currentMedicalInfo,
        ...info
    }

    const updatedCustomFields = {
        ...currentCustomFields,
        medical_info: newMedicalInfo
    }

    const updateData = {
        custom_fields: updatedCustomFields,
        // Also update top-level columns if they exist and are passed
        ...(info.birth_date ? { birth_date: info.birth_date } : {}),
    }

    const { data: result, error } = await supabase
        .from('crm_contacts')
        .update(updateData as never)
        .eq('id', contactId)
        .select()
        .single()

    if (error) throw new Error(error.message)

    revalidatePath(`/medical-records`)
    return result
}
